// Command specgen generates markdown documentation from the search field
// registry and data source catalog. Run it via:
//
//	go run ./cmd/specgen --output-dir docs/specs/generated
package main

import (
	"flag"
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/ketang/kapow/api/internal/search"
)

func main() {
	outputDir := flag.String("output-dir", "docs/specs/generated", "directory for generated markdown files")
	flag.Parse()

	if err := os.MkdirAll(*outputDir, 0o755); err != nil {
		fmt.Fprintf(os.Stderr, "specgen: create output dir: %v\n", err)
		os.Exit(1)
	}

	reg := search.NewRegistry()
	descriptors := reg.Descriptors()
	dataSources := search.AllDataSources()

	if err := writeSearchFields(filepath.Join(*outputDir, "search-fields.md"), descriptors); err != nil {
		fmt.Fprintf(os.Stderr, "specgen: write search-fields.md: %v\n", err)
		os.Exit(1)
	}

	if err := writeDataSources(filepath.Join(*outputDir, "data-sources.md"), dataSources); err != nil {
		fmt.Fprintf(os.Stderr, "specgen: write data-sources.md: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("specgen: wrote %s/search-fields.md (%d fields)\n", *outputDir, len(descriptors))
	fmt.Printf("specgen: wrote %s/data-sources.md (%d sources)\n", *outputDir, len(dataSources))
}

// writeSearchFields generates the search-fields.md reference document.
func writeSearchFields(path string, descriptors []search.FieldDescriptor) error {
	f, err := os.Create(path) //nolint:gosec // fixed output path
	if err != nil {
		return fmt.Errorf("specgen: create file: %w", err)
	}
	defer f.Close()

	var writeErr error
	w := func(format string, args ...any) {
		if writeErr != nil {
			return
		}
		_, writeErr = fmt.Fprintf(f, format, args...)
	}

	// Index fields by theme.
	byTheme := make(map[search.Theme][]search.FieldDescriptor)
	for _, d := range descriptors {
		byTheme[d.Theme] = append(byTheme[d.Theme], d)
	}

	w("# Search Fields Reference\n\n")
	w("> Auto-generated by `make spec-gen`. Do not edit manually.\n\n")

	for _, theme := range search.AllThemes {
		fields := byTheme[theme]
		if len(fields) == 0 {
			continue
		}

		w("## %s\n\n", search.ThemeLabel(theme))

		for _, fd := range fields {
			w("### %s\n\n", fd.Label)
			w("- **Name**: `%s`\n", fd.Name)
			w("- **Kind**: %s\n", string(fd.Kind))
			w("- **Description**: %s\n", fd.Description)
			if fd.DataSourceID != "" {
				w("- **Data Source**: %s\n", fd.DataSourceID)
			}
			if fd.Units != "" {
				w("- **Units**: %s\n", fd.Units)
			}
			if fd.Sortable {
				w("- **Sortable**: yes\n")
			} else {
				w("- **Sortable**: no\n")
			}

			// Enum options.
			if len(fd.Options) > 0 {
				w("- **Options**:\n")
				for _, opt := range fd.Options {
					if opt.Label != "" && opt.Label != opt.Value {
						w("  - `%s` — %s\n", opt.Value, opt.Label)
					} else {
						w("  - `%s`\n", opt.Value)
					}
				}
			}

			// Numeric bounds.
			if fd.Bounds != nil {
				parts := make([]string, 0, 2)
				if fd.Bounds.Min != nil {
					parts = append(parts, fmt.Sprintf("min: %g", *fd.Bounds.Min))
				}
				if fd.Bounds.Max != nil {
					parts = append(parts, fmt.Sprintf("max: %g", *fd.Bounds.Max))
				}
				if len(parts) > 0 {
					w("- **Bounds**: %s\n", strings.Join(parts, ", "))
				}
			}

			w("\n")
		}
	}

	// Summary section.
	w("## Summary\n\n")
	w("**Total fields**: %d\n\n", len(descriptors))
	w("| Theme | Count |\n")
	w("|---|---|\n")
	for _, theme := range search.AllThemes {
		if count := len(byTheme[theme]); count > 0 {
			w("| %s | %d |\n", search.ThemeLabel(theme), count)
		}
	}
	w("\n")

	if closeErr := f.Close(); closeErr != nil {
		return fmt.Errorf("specgen: close file: %w", closeErr)
	}
	return writeErr
}

// writeDataSources generates the data-sources.md reference document.
func writeDataSources(path string, sources []search.DataSource) error {
	f, err := os.Create(path) //nolint:gosec // fixed output path
	if err != nil {
		return fmt.Errorf("specgen: create file: %w", err)
	}
	defer f.Close()

	var writeErr error
	w := func(format string, args ...any) {
		if writeErr != nil {
			return
		}
		_, writeErr = fmt.Fprintf(f, format, args...)
	}

	w("# Data Sources Reference\n\n")
	w("> Auto-generated by `make spec-gen`. Do not edit manually.\n\n")

	w("| ID | Name | Short Name | Dataset Key | URL | Description |\n")
	w("|---|---|---|---|---|---|\n")
	for _, ds := range sources {
		w("| %s | %s | %s | `%s` | %s | %s |\n",
			ds.ID, ds.Name, ds.ShortName, ds.Dataset, ds.URL, ds.Description)
	}
	w("\n")

	if closeErr := f.Close(); closeErr != nil {
		return fmt.Errorf("specgen: close file: %w", closeErr)
	}
	return writeErr
}

